import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { HackathonService } from '../../../../core/services/hackathon.service';
import { TeamService } from '../../../../core/services/team.service';
import { HackathonSummaryDTO } from '../../../../core/models/hackathon.model';
import { TeamDTO } from '../../../../core/models/team.model';
import { HttpClient } from '@angular/common/http';

@Component({
  selector: 'app-my-hackathon',
  templateUrl: './my-hackathon.component.html',
  styleUrls: ['./my-hackathon.component.scss']
})
export class MyHackathonComponent implements OnInit {
  hackathon: HackathonSummaryDTO | null = null;
  myTeam: TeamDTO | null = null;
  activeTab: 'details' | 'segnalazioni' | 'sottomissioni' = 'details';

  // Segnalazioni
  segnalazioni: any[] = [];
  nuovaSegnalazione = '';
  segnalazioneLoading = false;
  segnalazioneError = '';
  segnalazioneSuccess = '';

  // Sottomissioni
  sottomissioni: any[] = [];
  nuovaSottomissione = { linkProgetto: '', descrizione: '' };
  sottomissioneLoading = false;
  sottomissioneError = '';
  sottomissioneSuccess = '';

  isLoading = true;
  errorMessage = '';

  private hackathonId = '';

  constructor(
    private route: ActivatedRoute,
    private hackathonService: HackathonService,
    private teamService: TeamService,
    private http: HttpClient
  ) {}

  ngOnInit(): void {
    this.hackathonId = this.route.snapshot.paramMap.get('id') || '';
    if (!this.hackathonId) {
      this.errorMessage = 'Hackathon non trovato.';
      this.isLoading = false;
      return;
    }
    this.loadData();
  }

  loadData(): void {
    // Load hackathon details
    this.hackathonService.getHackathonById(this.hackathonId).subscribe({
      next: (h) => {
        this.hackathon = h;
        this.isLoading = false;
      },
      error: () => {
        this.errorMessage = 'Impossibile caricare i dettagli dell\'hackathon.';
        this.isLoading = false;
      }
    });

    // Load user's team
    this.teamService.getMyTeams().subscribe({
      next: (teams) => { if (teams.length > 0) this.myTeam = teams[0]; }
    });
  }

  setTab(tab: 'details' | 'segnalazioni' | 'sottomissioni'): void {
    this.activeTab = tab;
    if (tab === 'segnalazioni' && this.segnalazioni.length === 0) this.loadSegnalazioni();
    if (tab === 'sottomissioni' && this.sottomissioni.length === 0) this.loadSottomissioni();
  }

  // --- Segnalazioni ---
  loadSegnalazioni(): void {
    const token = localStorage.getItem('token');
    this.http.get<any[]>(`/api/segnalazioni?hackathonId=${this.hackathonId}`, {
      headers: token ? { Authorization: token } : {}
    }).subscribe({
      next: (s) => this.segnalazioni = s,
      error: () => this.segnalazioneError = 'Impossibile caricare le segnalazioni.'
    });
  }

  inviaSegnalazione(): void {
    if (!this.nuovaSegnalazione.trim() || !this.myTeam) return;
    this.segnalazioneLoading = true;
    this.segnalazioneError = '';
    this.segnalazioneSuccess = '';
    const token = localStorage.getItem('token');
    const body = {
      idHackathon: this.hackathonId,
      idTeam: this.myTeam.id,
      descrizione: this.nuovaSegnalazione.trim()
    };
    this.http.post<any>('/api/segnalazioni/crea', body, {
      headers: token ? { Authorization: token } : {}
    }).subscribe({
      next: (s) => {
        this.segnalazioni.unshift(s);
        this.nuovaSegnalazione = '';
        this.segnalazioneSuccess = 'Segnalazione inviata con successo!';
        this.segnalazioneLoading = false;
      },
      error: (err) => {
        this.segnalazioneError = err.error?.message || 'Errore nell\'invio della segnalazione.';
        this.segnalazioneLoading = false;
      }
    });
  }

  // --- Sottomissioni ---
  loadSottomissioni(): void {
    const token = localStorage.getItem('token');
    this.http.get<any[]>('/api/submissions/my-submissions', {
      headers: token ? { Authorization: token } : {}
    }).subscribe({
      next: (s) => {
        // Filter only submissions for this hackathon
        this.sottomissioni = s.filter(sub =>
          sub.partecipazione?.hackathon?.id === this.hackathonId
        );
      },
      error: () => this.sottomissioneError = 'Impossibile caricare le sottomissioni.'
    });
  }

  inviaSottomissione(): void {
    if (!this.nuovaSottomissione.linkProgetto.trim() || !this.myTeam) return;
    this.sottomissioneLoading = true;
    this.sottomissioneError = '';
    this.sottomissioneSuccess = '';
    const token = localStorage.getItem('token');
    const body = {
      idHackathon: this.hackathonId,
      idTeam: this.myTeam.id,
      linkProgetto: this.nuovaSottomissione.linkProgetto.trim(),
      descrizione: this.nuovaSottomissione.descrizione.trim()
    };
    this.http.post<any>('/api/submissions', body, {
      headers: token ? { Authorization: token } : {}
    }).subscribe({
      next: (s) => {
        this.sottomissioni.unshift(s);
        this.nuovaSottomissione = { linkProgetto: '', descrizione: '' };
        this.sottomissioneSuccess = 'Sottomissione inviata con successo!';
        this.sottomissioneLoading = false;
      },
      error: (err) => {
        this.sottomissioneError = err.error?.message || 'Errore nell\'invio della sottomissione.';
        this.sottomissioneLoading = false;
      }
    });
  }

  getStatusDisplay(stato: string): string {
    const map: Record<string, string> = {
      'IN_ATTESA': 'In Attesa',
      'IN_ISCRIZIONE': 'Iscrizioni Aperte',
      'IN_CORSO': 'In Corso',
      'IN_VALUTAZIONE': 'In Valutazione',
      'IN_PREMIAZIONE': 'In Premiazione',
      'CONCLUSO': 'Concluso'
    };
    return map[stato] || stato;
  }
}
<div class="my-hackathon-container">

  <!-- Loading -->
  <div class="loading-state" *ngIf="isLoading">
    <div class="spinner"></div>
    <p>Caricamento hackathon...</p>
  </div>

  <!-- Error -->
  <div class="error-state" *ngIf="errorMessage && !isLoading">
    <div class="error-icon">⚠️</div>
    <p>{{ errorMessage }}</p>
  </div>

  <!-- Content -->
  <div *ngIf="hackathon && !isLoading">
    <!-- Header -->
    <div class="page-header">
      <div class="header-content">
        <div class="status-chip">{{ getStatusDisplay(hackathon.stato) }}</div>
        <h1 class="hackathon-title">🏆 {{ hackathon.nome }}</h1>
        <p class="hackathon-sub">{{ hackathon.luogo }} · {{ hackathon.organizzatoreNome }}</p>
      </div>
      <div class="team-badge" *ngIf="myTeam">
        <span>👥</span>
        <span>{{ myTeam.nome }}</span>
      </div>
    </div>

    <!-- Tabs -->
    <div class="tabs">
      <button class="tab" [class.active]="activeTab === 'details'" (click)="setTab('details')">
        📋 Dettagli
      </button>
      <button class="tab" [class.active]="activeTab === 'segnalazioni'" (click)="setTab('segnalazioni')">
        🚨 Segnalazioni
      </button>
      <button class="tab" [class.active]="activeTab === 'sottomissioni'" (click)="setTab('sottomissioni')">
        🚀 Sottomissioni
      </button>
    </div>

    <!-- TAB: Details -->
    <div class="tab-content" *ngIf="activeTab === 'details'">
      <div class="details-grid">
        <div class="detail-card">
          <div class="detail-icon">📅</div>
          <div>
            <div class="detail-label">Inizio Hackathon</div>
            <div class="detail-value">{{ hackathon.dataInizio | date:'dd MMM yyyy, HH:mm' }}</div>
          </div>
        </div>
        <div class="detail-card">
          <div class="detail-icon">🏁</div>
          <div>
            <div class="detail-label">Fine Hackathon</div>
            <div class="detail-value">{{ hackathon.dataFine | date:'dd MMM yyyy, HH:mm' }}</div>
          </div>
        </div>
        <div class="detail-card">
          <div class="detail-icon">📝</div>
          <div>
            <div class="detail-label">Iscrizioni</div>
            <div class="detail-value">{{ hackathon.inizioIscrizioni | date:'dd MMM' }} – {{ hackathon.scadenzaIscrizioni | date:'dd MMM yyyy' }}</div>
          </div>
        </div>
        <div class="detail-card">
          <div class="detail-icon">💰</div>
          <div>
            <div class="detail-label">Premio</div>
            <div class="detail-value prize">${{ hackathon.premioInDenaro }}</div>
          </div>
        </div>
        <div class="detail-card">
          <div class="detail-icon">📍</div>
          <div>
            <div class="detail-label">Luogo</div>
            <div class="detail-value">{{ hackathon.luogo || 'Online' }}</div>
          </div>
        </div>
        <div class="detail-card">
          <div class="detail-icon">👤</div>
          <div>
            <div class="detail-label">Organizzatore</div>
            <div class="detail-value">{{ hackathon.organizzatoreNome || 'N/A' }}</div>
          </div>
        </div>
      </div>
      <div class="regolamento-card">
        <h3>📜 Regolamento</h3>
        <p>{{ hackathon.regolamento }}</p>
      </div>
    </div>

    <!-- TAB: Segnalazioni -->
    <div class="tab-content" *ngIf="activeTab === 'segnalazioni'">
      <!-- List -->
      <div class="list-section">
        <h3>Segnalazioni ({{ segnalazioni.length }})</h3>
        <div class="empty-hint" *ngIf="segnalazioni.length === 0">
          Nessuna segnalazione ancora.
        </div>
        <div class="item-card" *ngFor="let s of segnalazioni">
          <div class="item-header">
            <span class="item-team">👥 {{ s.teamNome || s.team?.nomeTeam || 'Team' }}</span>
            <span class="item-date">{{ s.dataSegnalazione | date:'dd MMM yyyy' }}</span>
          </div>
          <p class="item-body">{{ s.descrizione }}</p>
        </div>
      </div>
    </div>

    <!-- TAB: Sottomissioni -->
    <div class="tab-content" *ngIf="activeTab === 'sottomissioni'">
      <!-- Submit form -->
      <div class="form-card" *ngIf="myTeam">
        <h3>Invia una Sottomissione</h3>
        <div class="alert alert-success" *ngIf="sottomissioneSuccess">{{ sottomissioneSuccess }}</div>
        <div class="alert alert-error" *ngIf="sottomissioneError">{{ sottomissioneError }}</div>
        <div class="form-group">
          <label class="form-label">Link Progetto *</label>
          <input
            class="form-input"
            type="url"
            placeholder="https://github.com/..."
            [(ngModel)]="nuovaSottomissione.linkProgetto">
        </div>
        <div class="form-group">
          <label class="form-label">Descrizione</label>
          <textarea
            class="form-textarea"
            placeholder="Descrivi brevemente il tuo progetto..."
            [(ngModel)]="nuovaSottomissione.descrizione"
            rows="3">
          </textarea>
        </div>
        <button class="btn-primary" (click)="inviaSottomissione()" [disabled]="sottomissioneLoading || !nuovaSottomissione.linkProgetto.trim()">
          <span *ngIf="!sottomissioneLoading">🚀 Invia Sottomissione</span>
          <span *ngIf="sottomissioneLoading">Invio...</span>
        </button>
      </div>

      <!-- List -->
      <div class="list-section">
        <h3>Le tue Sottomissioni ({{ sottomissioni.length }})</h3>
        <div class="empty-hint" *ngIf="sottomissioni.length === 0">
          Nessuna sottomissione ancora. Invia il tuo progetto!
        </div>
        <div class="item-card" *ngFor="let s of sottomissioni">
          <div class="item-header">
            <span class="item-team">🚀 Sottomissione</span>
            <span class="item-date">{{ s.dataSottomissione | date:'dd MMM yyyy, HH:mm' }}</span>
          </div>
          <a [href]="s.linkProgetto" target="_blank" class="project-link">🔗 {{ s.linkProgetto }}</a>
          <p class="item-body" *ngIf="s.descrizione">{{ s.descrizione }}</p>
        </div>
      </div>
    </div>
  </div>
</div>
